/**
 * @file linked_list_processor.cpp
 * @brief Contains a function to process a singly linked list by multiplying each node's value by its position
 */

/**
 * @struct Node
 * @brief Represents a node in a singly linked list
 * @param value Integer value stored in the node
 * @param next Pointer to the next node in the list
 */
struct Node {
    int value;
    Node* next;

    // Constructor for convenience
    Node(int val) : value(val), next(nullptr) {}
};

/**
 * @function processLinkedList
 * @brief Multiplies each node's value by its position in the list (1-indexed)
 * @param head Pointer to the head of the linked list
 * @return Pointer to the head of the modified linked list
 * @note The function handles edge cases such as empty lists
 * @note Time complexity: O(n) where n is the number of nodes in the list
 * @note Space complexity: O(1) as the operation is performed in-place
 */
Node* processLinkedList(Node* head) {
    // Edge case: empty list
    if (head == nullptr) {
        return nullptr;
    }

    Node* current = head;
    int position = 1; // 1-indexed position

    // Traverse the list and modify each node's value
    while (current != nullptr) {
        // Multiply node value by its position
        current->value *= position;

        // Move to the next node
        current = current->next;
        position++;
    }

    return head;
}
