/// Sorts a list of numbers in ascending order.
/// This function uses Rust's built-in sort_by method with a comparator that safely handles both
/// integers and floating points.
/// 
/// # Arguments
/// * `numbers` - A vector that contains f64 values to be sorted
/// 
/// # Returns
/// * `Result<Vec<f64>, String>` - The sorted vector or an error message
pub fn sort_numbers(numbers: Vec<f64>) -> Result<Vec<f64>, String> {
    // Input validation - check if all elements are finite numbers
    for num in &numbers {
        if !num.is_finite() {
            return Err(format!("Invalid input: {} is not a valid number", num));
        }
    }

    // Create a mutable copy of the input vector
    let mut sorted_numbers = numbers.clone();

    // Sort the numbers in ascending order
    // Using sort_by with partial_cmp handles potential NaN values properly
    sorted_numbers.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));

    Ok(sorted_numbers)
}
