use std::collections::{HashMap, HashSet, VecDeque};

// Define the Graph structure
struct Graph {
    nodes: HashMap<String, Vec<String>>,
}

impl Graph {
    fn new() -> Self {
        Graph {
            nodes: HashMap::new(),
        }
    }

    fn add_node(&mut self, node: &str) {
        self.nodes.entry(node.to_string()).or_insert(Vec::new());
    }

    fn add_edge(&mut self, from: &str, to: &str) {
        self.add_node(from);
        self.add_node(to);
        if let Some(edges) = self.nodes.get_mut(from) {
            if !edges.contains(&to.to_string()) {
                edges.push(to.to_string());
            }
        }
    }
}

enum SearchStrategy {
    DFS,
    BFS,
}

enum PathError {
    NodeNotFound(String),
    NoPathExists,
}

fn find_path(
    graph: &Graph,
    start: &str,
    end: &str,
    strategy: SearchStrategy,
) -> Result<Vec<String>, PathError> {
    // Validate that start and end nodes exist
    if !graph.nodes.contains_key(start) {
        return Err(PathError::NodeNotFound(start.to_string()));
    }
    if !graph.nodes.contains_key(end) {
        return Err(PathError::NodeNotFound(end.to_string()));
    }

    let mut visited = HashSet::new();
    let mut parent_map: HashMap<String, String> = HashMap::new();

    match strategy {
        SearchStrategy::DFS => {
            // Perform DFS
            if !dfs(graph, start, end, &mut visited, &mut parent_map) {
                return Err(PathError::NoPathExists);
            }
        }
        SearchStrategy::BFS => {
            // Perform BFS
            if !bfs(graph, start, end, &mut visited, &mut parent_map) {
                return Err(PathError::NoPathExists);
            }
        }
    }

    // Reconstruct the path from end to start
    let mut path = Vec::new();
    let mut current = end.to_string();

    while current != start {
        path.push(current.clone());
        current = parent_map.get(&current).unwrap().clone();
    }

    path.push(start.to_string());
    path.reverse();

    Ok(path)
}

fn dfs(
    graph: &Graph,
    current: &str,
    end: &str,
    visited: &mut HashSet<String>,
    parent_map: &mut HashMap<String, String>,
) -> bool {
    if current == end {
        return true;
    }

    visited.insert(current.to_string());

    if let Some(neighbors) = graph.nodes.get(current) {
        for neighbor in neighbors {
            if !visited.contains(neighbor) {
                parent_map.insert(neighbor.clone(), current.to_string());
                if dfs(graph, neighbor, end, visited, parent_map) {
                    return true;
                }
            }
        }
    }

    false
}

fn bfs(
    graph: &Graph,
    start: &str,
    end: &str,
    visited: &mut HashSet<String>,
    parent_map: &mut HashMap<String, String>,
) -> bool {
    let mut queue = VecDeque::new();
    queue.push_back(start.to_string());
    visited.insert(start.to_string());

    while let Some(current) = queue.pop_front() {
        if current == end {
            return true;
        }

        if let Some(neighbors) = graph.nodes.get(&current) {
            for neighbor in neighbors {
                if !visited.contains(neighbor) {
                    visited.insert(neighbor.clone());
                    parent_map.insert(neighbor.clone(), current.clone());
                    queue.push_back(neighbor.clone());
                }
            }
        }
    }

    false
}
