#include <iostream>
#include <vector>
#include <queue>
#include <limits>
#include <unordered_map>
#include <stdexcept>

std::vector<int> findShortestPath(const std::unordered_map<int, std::vector<std::pair<int, int>>>& graph, 
                                  int startNode, int endNode) {
    // Error handling for non-existent nodes
    if (graph.find(startNode) == graph.end()) {
        throw std::invalid_argument("Starting node does not exist in the graph");
    }
    if (graph.find(endNode) == graph.end()) {
        throw std::invalid_argument("Ending node does not exist in the graph");
    }

    // Priority queue for Dijkstra's algorithm (distance, node)
    std::priority_queue<std::pair<int, int>, 
                        std::vector<std::pair<int, int>>, 
                        std::greater<std::pair<int, int>>> pq;

    // Distance map and predecessor map
    std::unordered_map<int, int> distance;
    std::unordered_map<int, int> predecessor;

    // Initialize distances to infinity
    for (const auto& node : graph) {
        distance[node.first] = std::numeric_limits<int>::max();
        predecessor[node.first] = -1;
    }

    // Distance to start node is 0
    distance[startNode] = 0;
    pq.push({0, startNode});

    // Dijkstra's algorithm
    while (!pq.empty()) {
        int currentDist = pq.top().first;
        int currentNode = pq.top().second;
        pq.pop();

        // If we reached the destination, we can stop
        if (currentNode == endNode) {
            break;
        }

        // If this is not the shortest distance, skip
        if (currentDist > distance[currentNode]) {
            continue;
        }

        // Check all neighbors
        for (const auto& neighbor : graph.at(currentNode)) {
            int nextNode = neighbor.first;
            int weight = neighbor.second;

            if (distance[currentNode] + weight < distance[nextNode]) {
                distance[nextNode] = distance[currentNode] + weight;
                predecessor[nextNode] = currentNode;
                pq.push({distance[nextNode], nextNode});
            }
        }
    }

    // If no path exists
    if (distance[endNode] == std::numeric_limits<int>::max()) {
        return {};  // Return empty path
    }

    // Reconstruct the path
    std::vector<int> path;
    for (int at = endNode; at != -1; at = predecessor[at]) {
        path.push_back(at);
    }

    // Reverse to get path from start to end
    std::reverse(path.begin(), path.end());

    return path;
}
