public List<Integer> analyzeGraphTraversal(Graph graph, boolean useBFS) {
    if (graph == null || graph.getVertices().isEmpty()) {
        return new ArrayList<>();
    }

    List<Integer> visitedOrder = new ArrayList<>();
    Set<Integer> visited = new HashSet<>();
    Map<Integer, List<Integer>> adjacencyList = graph.getAdjacencyList();

    for (Integer startVertex : graph.getVertices()) {
        if (!visited.contains(startVertex)) {
            if (useBFS) {
                bfsTraversal(startVertex, adjacencyList, visited, visitedOrder);
            } else {
                dfsTraversal(startVertex, adjacencyList, visited, visitedOrder);
            }
        }
    }

    return visitedOrder;
}

private void bfsTraversal(Integer startVertex, Map<Integer, List<Integer>> adjacencyList, 
                          Set<Integer> visited, List<Integer> visitedOrder) {
    Queue<Integer> queue = new LinkedList<>();
    queue.offer(startVertex);
    visited.add(startVertex);

    while (!queue.isEmpty()) {
        Integer current = queue.poll();
        visitedOrder.add(current);
        System.out.println("Visiting node: " + current);

        List<Integer> neighbors = adjacencyList.getOrDefault(current, Collections.emptyList());
        for (Integer neighbor : neighbors) {
            if (!visited.contains(neighbor)) {
                visited.add(neighbor);
                queue.offer(neighbor);
            }
        }
    }
}

private void dfsTraversal(Integer vertex, Map<Integer, List<Integer>> adjacencyList, 
                         Set<Integer> visited, List<Integer> visitedOrder) {
    visited.add(vertex);
    visitedOrder.add(vertex);
    System.out.println("Visiting node: " + vertex);

    List<Integer> neighbors = adjacencyList.getOrDefault(vertex, Collections.emptyList());
    for (Integer neighbor : neighbors) {
        if (!visited.contains(neighbor)) {
            dfsTraversal(neighbor, adjacencyList, visited, visitedOrder);
        }
    }
}
