std::vector<int> computeShortestPathFromNode(const std::vector<std::vector<int>>& adjacencyMatrix, int startNode) {
    // Error handling for invalid starting node
    if (startNode < 0 || startNode >= adjacencyMatrix.size()) {
        throw std::invalid_argument("Invalid starting node index");
    }

    // Check if matrix is valid
    size_t n = adjacencyMatrix.size();
    for (const auto& row : adjacencyMatrix) {
        if (row.size() != n) {
            throw std::invalid_argument("Invalid adjacency matrix: matrix must be square");
        }
    }

    // Initialize distances vector
    std::vector<int> distances(n, INT_MAX);
    distances[startNode] = 0;

    // Initialize visited vector
    std::vector<bool> visited(n, false);

    // Dijkstra's algorithm
    for (size_t i = 0; i < n; ++i) {
        // Find the minimum distance vertex from the set of unvisited vertices
        int minDist = INT_MAX;
        int minIndex = -1;

        for (size_t j = 0; j < n; ++j) {
            if (!visited[j] && distances[j] < minDist) {
                minDist = distances[j];
                minIndex = j;
            }
        }

        // If no minimum index was found, break
        if (minIndex == -1) break;

        // Mark vertex as visited
        visited[minIndex] = true;

        // Update distances of adjacent vertices
        for (size_t j = 0; j < n; ++j) {
            // Check if there is an edge from minIndex to j
            if (adjacencyMatrix[minIndex][j] > 0) {
                // Check if the new path is shorter
                if (!visited[j] && 
                    distances[minIndex] != INT_MAX && 
                    distances[minIndex] + adjacencyMatrix[minIndex][j] < distances[j]) {
                    distances[j] = distances[minIndex] + adjacencyMatrix[minIndex][j];
                }
            }
        }
    }

    return distances;
}
