        total_age as f64 / valid_age_count as f64
    } else {
        println!("Warning: No valid age data found");
        0.0
    };

    // Find most frequent occupation
    let most_frequent_occupation = occupation_counts.iter()
        .max_by_key(|(_, &count)| count)
        .map(|(occupation, count)| (occupation.clone(), *count));

    // Find most common city
    let most_common_city = city_counts.iter()
        .max_by_key(|(_, &count)| count)
        .map(|(city, count)| (city.clone(), *count));

    // Log results
    println!("User Statistics:");
    println!("Average Age: {:.2}", average_age);

    match most_frequent_occupation {
        Some((occupation, count)) => println!("Most Frequent Occupation: {} (count: {})", occupation, count),
