import os
import shutil
import logging

def batch_file_transfer(filenames, destination_directory):
    # Configure logging
    logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

    # Check if destination directory exists
    if not os.path.exists(destination_directory):
        try:
            os.makedirs(destination_directory)
            logging.info(f"Created destination directory: {destination_directory}")
        except Exception as e:
            logging.error(f"Failed to create destination directory: {destination_directory}. Error: {str(e)}")
            return

    # Process each file
    for filename in filenames:
        try:
            if not os.path.exists(filename):
                logging.error(f"Transfer failed: File '{filename}' does not exist")
                continue

            destination_path = os.path.join(destination_directory, os.path.basename(filename))
            shutil.copy2(filename, destination_path)
            logging.info(f"Transfer successful: '{filename}' copied to '{destination_path}'")

        except PermissionError:
            logging.error(f"Transfer failed: Permission denied for file '{filename}'")
        except IsADirectoryError:
            logging.error(f"Transfer failed: '{filename}' is a directory, not a file")
        except shutil.SameFileError:
            logging.error(f"Transfer failed: Source '{filename}' and destination '{destination_path}' are the same file")
        except Exception as e:
            logging.error(f"Transfer failed: Error copying '{filename}': {str(e)}")
