bool updateTableSchema(const std::string& tableName, const JSONObject& schemaDefinitions) {
    try {
        // Check if table exists
        if (!tableExists(tableName)) {
            std::cerr << "Error: Table '" << tableName << "' does not exist." << std::endl;
            return false;
        }

        // Construct ALTER TABLE statement
        std::string alterQuery = "ALTER TABLE " + tableName + " ";

        // Process schema definitions
        bool firstChange = true;
        for (const auto& definition : schemaDefinitions) {
            if (!firstChange) {
                alterQuery += ", ";
            }

            // Extract column modification details
            std::string columnName = definition.first;
            std::string columnType = definition.second["type"].toString();
            bool isNullable = definition.second["nullable"].toBool();

            // Build appropriate ALTER clause based on operation type
            std::string operation = definition.second["operation"].toString();
            if (operation == "ADD") {
                alterQuery += "ADD COLUMN " + columnName + " " + columnType;
            } else if (operation == "MODIFY") {
                alterQuery += "MODIFY " + columnName + " " + columnType;
            } else if (operation == "DROP") {
                alterQuery += "DROP COLUMN " + columnName;
            }

            // Add NULL/NOT NULL constraint for ADD or MODIFY operations
            if (operation != "DROP") {
                alterQuery += isNullable ? " NULL" : " NOT NULL";
            }

            firstChange = false;
        }

        // Execute the ALTER TABLE statement
        Database::executeQuery(alterQuery);
        std::cout << "Schema updated successfully for table '" << tableName << "'." << std::endl;
        return true;
    } catch (const DatabaseException& e) {
        std::cerr << "Database error during schema update: " << e.what() << std::endl;
        return false;
    } catch (const std::exception& e) {
        std::cerr << "Error during schema update: " << e.what() << std::endl;
        return false;
    }
}
